firmware_template.source:
#include "ir_transmitter.h"
#include <IRsend.h>
#define IR_TX_PIN 4
static IRsend irsend(IR_TX_PIN);
void ir_tx_setup(){irsend.begin();Serial.println("[ir_tx] OK");}
void ir_tx_send_nec(uint32_t code){irsend.sendNEC(code);}
void ir_tx_send_raw(const uint16_t*d,uint16_t l,uint16_t f){irsend.sendRaw(d,l,f);}
